export const VOCAB_BY_AGE: Record<string, { word: string; meaning: string; example: string }[]> = Object.fromEntries(
  Object.entries(VOCAB_BY_AGE_RAW).map(([ageGroup, entries], index) => {
    const normalizedAgeGroup = ageGroup as AgeGroup;
    return [ageGroup, expandAgeGroup(entries, normalizedAgeGroup, index * 97, AGE_VOCAB_TARGET_COUNTS[normalizedAgeGroup])];
  }),
) as Record<string, { word: string; meaning: string; example: string }[]>;
